const handlePredict = async () => {
  if (!activeId) {
    onNotify("⚠️ Entraînez un modèle d'abord", "warning");
    return;
  }

  setLoading(true);

  try {
    const res = await predict({
      model_id: activeId,
      features: inputs
    });

    setResult(res);
  } catch (err) {
    onNotify(`❌ ${err.message}`, "error");
  } finally {
    setLoading(false);
  }
};
